 22	import { isEmpty } from '@utils/helpers';
 23	
 24	import type { Mapping, MappingSource } from '../types';
 25	
 26	import '../ProvidersCreateVmMigration.style.css';
 27	
 28	const toGroup = (sources: MappingSource[], noSourcesLabel: string, selectedSource: string) =>
 29	  isEmpty(sources) ? (
 30	    <SelectOption value={noSourcesLabel} isDisabled={true}>
 31	      {noSourcesLabel}
 32	    </SelectOption>
 33	  ) : (
 34	    sources.map(({ isMapped, label }) => (
 35	      <SelectOption value={label} key={label} isDisabled={isMapped && label !== selectedSource}>
 36	        {label}
 37	      </SelectOption>
 38	    ))
 39	  );
 40	
 41	type MappingListItemProps = {
 42	  source: string;
 43	  destination: string;
 44	  destinations: string[];
 45	  generalSources: MappingSource[];
 46	  usedSources: MappingSource[];
 47	  usedSourcesLabel: string;
 48	  generalSourcesLabel: string;
 49	  noSourcesLabel: string;
 50	  index: number;
 51	  replaceMapping: (val: { current: Mapping; next: Mapping }) => void;
 52	  deleteMapping: (mapping: Mapping) => void;
 53	  isDisabled: boolean;
 54	};
 55	
 56	export const MappingListItem: FC<MappingListItemProps> = ({
 57	  deleteMapping,
 58	  destination,
 59	  destinations,
 60	  generalSources,
 61	  generalSourcesLabel,
 62	  index,
 63	  isDisabled,
 64	  noSourcesLabel,
 65	  replaceMapping,
 66	  source,
 67	  usedSources,
 68	  usedSourcesLabel,
 69	}) => {
 70	  const { t } = useForkliftTranslation();
 71	  const [isSrcOpen, setIsSrcOpen] = useState(false);
 72	  const [isTrgOpen, setIsTrgOpen] = useState(false);
 73	  const [srcSelected, setSrcSelected] = useState<string>(source);
 74	  const [trgSelected, setTrgSelected] = useState<string>(destination);
 75	
 76	  const onClick = () => {
 77	    deleteMapping({ destination, source });
 78	  };
 79	
 80	  const onSrcToggleClick = () => {
 81	    setIsSrcOpen(!isSrcOpen);
 82	  };
 83	
 84	  const onTrgToggleClick = () => {
 85	    setIsTrgOpen(!isTrgOpen);
 86	  };
 87	
 88	  const srcToggle = (toggleRef: Ref<MenuToggleElement>) => (
 89	    <MenuToggle ref={toggleRef} onClick={onSrcToggleClick} isExpanded={isSrcOpen} isFullWidth>
 90	      {srcSelected}
 91	    </MenuToggle>
 92	  );
 93	
 94	  const trgToggle = (toggleRef: Ref<MenuToggleElement>) => (
 95	    <MenuToggle ref={toggleRef} onClick={onTrgToggleClick} isExpanded={isTrgOpen} isFullWidth>
 96	      {trgSelected}
 97	    </MenuToggle>
 98	  );
 99	
100	  // Callback functions to handle selection in the dropdown menus
101	  const onSelectSource = (_event: MouseEvent | undefined, value: string | number | undefined) => {
102	    replaceMapping({
103	      current: { destination, source },
104	      next: { destination, source: value as string },
105	    });
106	
107	    // Toggle the dropdown menu open state
108	    setSrcSelected(value as string);
109	    setIsSrcOpen(false);
110	  };
111	
112	  const onSelectDestination = (
113	    _event: MouseEvent | undefined,
114	    value: string | number | undefined,
115	  ) => {
116	    replaceMapping({
117	      current: { destination, source },
118	      next: { destination: value as string, source },
119	    });
120	
121	    // Toggle the dropdown menu open state
122	    setTrgSelected(value as string);
123	    setIsTrgOpen(false);
124	  };
125	
126	  return (
127	    <DataListItem aria-labelledby="">
128	      <DataListItemRow>
129	        <DataListItemCells
130	          dataListCells={[
131	            <DataListCell key="source">
132	              <Form>
133	                <FormGroup label={t('Source')}>
134	                  {/* Custom select does not support the complex toggle being used here */}
135	                  {/* eslint-disable-next-line no-restricted-syntax */}
136	                  <Select
137	                    role="menu"
138	                    aria-label=""
139	                    aria-labelledby=""
140	                    isOpen={isSrcOpen}
141	                    selected={srcSelected}
142	                    onSelect={onSelectSource}
143	                    onOpenChange={(nextOpen: boolean) => {
144	                      setIsSrcOpen(nextOpen);
145	                    }}
146	                    toggle={srcToggle}
147	                    shouldFocusToggleOnSelect
148	                    shouldFocusFirstItemOnOpen={false}
149	                    isScrollable
150	                    popperProps={{
151	                      direction: 'down',
152	                      enableFlip: true,
153	                    }}
154	                  >
155	                    <SelectList>
156	                      <SelectGroup label={usedSourcesLabel} key="usedSources">
157	                        {toGroup(usedSources, noSourcesLabel, source)}
158	                      </SelectGroup>
159	                      <SelectGroup label={generalSourcesLabel} key="generalSources">
160	                        {toGroup(generalSources, noSourcesLabel, source)}
161	                      </SelectGroup>
162	                    </SelectList>
163	                  </Select>
164	                </FormGroup>
165	              </Form>
166	            </DataListCell>,
167	            <DataListCell key="destination">
168	              <Form>
169	                <FormGroup label={t('Target')}>
170	                  {/* Custom select does not support the complex toggle being used here */}
171	                  {/* eslint-disable-next-line no-restricted-syntax */}
172	                  <Select
173	                    role="menu"
174	                    aria-label=""
175	                    aria-labelledby=""
176	                    isOpen={isTrgOpen}
177	                    selected={trgSelected}
178	                    onSelect={onSelectDestination}
179	                    onOpenChange={(nextOpen: boolean) => {
180	                      setIsTrgOpen(nextOpen);
181	                    }}
182	                    toggle={trgToggle}
183	                    shouldFocusToggleOnSelect
184	                    shouldFocusFirstItemOnOpen={false}
185	                    isScrollable
186	                    popperProps={{
187	                      direction: 'down',
188	                      enableFlip: true,
189	                    }}
190	                  >
191	                    <SelectList>
192	                      {destinations.map((label) => (
193	                        <SelectOption value={label} key={label}>
194	                          {label}
195	                        </SelectOption>
196	                      ))}
197	                    </SelectList>
198	                  </Select>
199	                </FormGroup>
200	              </Form>
201	            </DataListCell>,
202	          ]}
203	        />
204	        <DataListAction
205	          id={`mapping_list_item_${index}`}
206	          aria-label={t('Actions')}
