209	        >
210	          <Button
211	            onClick={onClick}
212	            variant={ButtonVariant.plain}
213	            aria-label={t('Delete mapping')}
214	            key="delete-action"
215	            icon={<MinusCircleIcon />}
216	            isDisabled={isDisabled}
217	          />
218	        </DataListAction>
219	      </DataListItemRow>
220	    </DataListItem>
221	  );
222	};

